public int numSteps(String s) {
    int steps = 0, carry = 0;
    for (int i = s.length() - 1; i > 0; --i) {
        int bit = s.charAt(i) - '0';
        if (bit == 1 && carry == 1) {
            carry = 1;
            steps += 2;
        } else if (bit == 1 || carry == 1) {
            carry ^= 1;
            steps += 2;
        } else {
            steps++;
        }
    }

    return steps + carry;
}
```

